<!-- жҲ‘зҡ„йЎөйқў -->
<template>
  <scroll-view class="mine-page" scroll-y>
    <view class="blue-header">
      <view class="header-top">
        <view class="avatar-wrap">
          <uni-id-pages-avatar width="120rpx" height="120rpx"></uni-id-pages-avatar>
        </view>
        <view class="user-info">
          <text class="nickname">{{ displayNickname }}</text>
          <text class="uid" v-if="userInfo.studentNo">еӯҰеҸ·: {{ userInfo.studentNo }}</text>
          <text class="uid" v-else-if="!userInfo._id">жңӘзҷ»еҪ•</text>
        </view>
        <text class="edit-btn" @click="userInfo._id ? setNickname('') : login()">{{ userInfo._id ? 'зј–иҫ‘еҗҚз§°' : 'зҷ»еҪ•' }}</text>
      </view>
    </view>

    <view class="orange-card" v-if="!isRiderMode" @click="goBecomeRider">
      <view class="orange-left">
        <image class="orange-icon-img" src="/static/tabbar/kuaididaiqu.png" mode="aspectFit" />
      </view>
      <view class="orange-middle">
        <text class="orange-title">жҲҗдёәйӘ‘жүӢ</text>
        <text class="orange-sub">ејҖеҗҜжҺҘеҚ•жЁЎејҸпјҢиөҡеҸ–йўқеӨ–ж”¶е…Ҙ</text>
      </view>
    </view>

    <view class="menu-card">
      <view class="menu-item" @click="goWallet">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/wodeqianbao.png" mode="aspectFit" />
          <text class="menu-text">жҲ‘зҡ„й’ұеҢ…</text>
        </view>
        <view class="menu-right">
          <text class="menu-extra">ВҘ{{ walletAmount }}</text>
        </view>
      </view>

      <view class="menu-item" @click="goAddress">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/wodedizhi.png" mode="aspectFit" />
          <text class="menu-text">ж”¶иҙ§ең°еқҖ</text>
        </view>
      </view>

      <view class="menu-item" @click="goMessages">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/xiaoxitonzhi.png" mode="aspectFit" />
          <text class="menu-text">ж¶ҲжҒҜйҖҡзҹҘ</text>
        </view>
      </view>

      <view class="menu-item" @click="goService">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/zaixiankefu.png" mode="aspectFit" />
          <text class="menu-text">ж ЎдәӢеұӢе®ўжңҚ</text>
        </view>
      </view>

      <view class="menu-item" @click="goHelp">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/bangzhuzhonxin.png" mode="aspectFit" />
          <text class="menu-text">е»әи®®&жҠ•иҜү</text>
        </view>
      </view>

      <view class="menu-item" @click="goSettings">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/shezhi.png" mode="aspectFit" />
          <text class="menu-text">и®ҫзҪ®</text>
        </view>
      </view>

      <view class="menu-item" @click="goAgreements">
        <view class="menu-left">
          <image class="menu-icon-img" src="/static/tabbar/bangzhuzhonxin.png" mode="aspectFit" />
          <text class="menu-text">еҚҸи®®дёҺйҡҗз§Ғ</text>
        </view>
      </view>
    </view>

    <view class="menu-card" v-if="isRiderMode">
      <view class="menu-item" @click="goClientMode">
        <view class="menu-left">
          <text class="menu-icon">вҶ©пёҸ</text>
          <text class="menu-text">еҲҮеӣһз”ЁжҲ·з«Ҝ</text>
        </view>
      </view>
    </view>

    <view class="logout-row" v-if="showLoginManage">
      <button v-if="userInfo._id" class="logout-btn" @click="logout">йҖҖеҮәзҷ»еҪ•</button>
      <button v-else class="login-btn" @click="login">еҺ»зҷ»еҪ•</button>
    </view>

    <uni-popup ref="dialog" type="dialog">
      <uni-popup-dialog
        mode="input"
        :value="userInfo.nickname"
        @confirm="setNickname"
        :inputType="setNicknameIng?'nickname':'text'"
        title="и®ҫзҪ®жҳөз§°"
        placeholder="иҜ·иҫ“е…ҘиҰҒи®ҫзҪ®зҡ„жҳөз§°"
      />
    </uni-popup>

    <uni-popup ref="servicePopup" type="center">
      <view class="service-popup" @click.stop>
        <text class="service-popup-title">ж ЎдәӢеұӢе®ўжңҚ</text>
        <text class="service-popup-subtitle">дё“дёҡж ЎеӣӯжңҚеҠЎпјҢз”ЁеҝғдёәжӮЁи§Јзӯ”</text>
        <text class="service-popup-phone">{{ servicePhone }}</text>
      <view class="service-popup-actions">
          <!-- еҫ®дҝЎе°ҸзЁӢеәҸеҶ…зӣҙжҺҘе”Өиө·еңЁзәҝе®ўжңҚдјҡиҜқ -->
          <!-- #ifdef MP-WEIXIN -->
          <button
            class="service-popup-btn primary"
            open-type="contact"
            session-from="mine_service"
            @contact="onContact"
          >еңЁзәҝе®ўжңҚ</button>
          <!-- #endif -->
          <!-- е…¶д»–з«ҜдёҚж”ҜжҢҒеңЁзәҝе®ўжңҚж—¶пјҢжҸҗдҫӣеӨҚеҲ¶еҸ·з ҒдҪңдёәйҷҚзә§ж–№жЎҲ -->
          <!-- #ifndef MP-WEIXIN -->
          <button class="service-popup-btn primary" @click="copyServicePhone">еӨҚеҲ¶еҸ·з Ғ</button>
          <!-- #endif -->
          <button class="service-popup-btn ghost" @click="callServicePhone">жӢЁжү“з”өиҜқ</button>
          <button class="service-popup-btn ghost" @click="closeServicePopup">е…ій—ӯ</button>
      </view>
      </view>
    </uni-popup>

    <uni-popup ref="riderJoinPopup" type="center">
      <view class="service-popup" @click.stop>
        <text class="service-popup-title">йӘ‘жүӢеҠ зҫӨжҢҮеј•</text>
        <text class="service-popup-subtitle">{{ riderGuide.tip || 'жү«жҸҸдәҢз»ҙз Ғж·»еҠ йӘ‘жүӢзҫӨ' }}</text>
        <image
          v-if="riderGuide.qr_file_id"
          class="rider-guide-qr"
          :src="riderGuide.qr_file_id"
          mode="aspectFit"
          @click="previewRiderGuideQr"
        />
        <text v-else class="service-popup-subtitle">жҡӮжңӘй…ҚзҪ®зҫӨдәҢз»ҙз ҒпјҢиҜ·иҒ”зі»з®ЎзҗҶе‘ҳ</text>
        <view class="service-popup-actions">
          <button class="service-popup-btn ghost" @click="closeRiderJoinPopup">е…ій—ӯ</button>
        </view>
      </view>
    </uni-popup>
    <uni-id-pages-bind-mobile ref="bind-mobile-by-sms" @success="bindMobileSuccess"></uni-id-pages-bind-mobile>
  </scroll-view>
  <TheTabBar />
</template>
<script>
const uniIdCo = uniCloud.importObject("uni-id-co")
const riderService = uniCloud.importObject("rider-service")
  import {
    store,
    mutations
  } from '@/uni_modules/uni-id-pages/common/store.js'
  import { isRiderMode as checkRiderMode, switchToRider, switchToClient } from '@/store/user.js'
  import { useWalletStore } from '@/store/wallet.js'
  import TheTabBar from '@/components/TheTabBar.vue'
	export default {
    components: {
      TheTabBar
    },
    computed: {
      userInfo() {
        return store.userInfo
      },
      displayNickname() {
        if (this.userInfo.nickname) return this.userInfo.nickname
        if (this.userInfo._id) return this.getDefaultNickname()
        return 'зӮ№еҮ»зҷ»еҪ•/е®Ңе–„иө„ж–ҷ'
      },
      isRiderMode() {
        return checkRiderMode()
      },
	    realNameStatus () {
		    if (!this.userInfo.realNameAuth) {
			    return 0
		    }

		    return this.userInfo.realNameAuth.authStatus
      },
      walletAmount() {
        return this.walletStore ? this.walletStore.balance : 0
      }
    },
		data() {
			return {
				univerifyStyle: {
					authButton: {
						"title": "жң¬жңәеҸ·з ҒдёҖй”®з»‘е®ҡ", // жҺҲжқғжҢүй’®ж–ҮжЎҲ
					},
					otherLoginButton: {
						"title": "е…¶д»–еҸ·з Ғз»‘е®ҡ",
					}
				},
				hasPwd: false,
				showLoginManage: true,
				setNicknameIng:false,
        stats: {
          totalOrders: 23,
          credit: 4.9,
          points: 580
        },
        walletStore: null,
        couponCount: 3,
        servicePhone: '18608945191',
        riderGuide: {
          title: 'жҸҗзҺ°иҜ·зӮ№жҲ‘зҡ„',
          tip: 'жү«жҸҸдәҢз»ҙз Ғж·»еҠ йӘ‘жүӢзҫӨ',
          qr_file_id: '',
          enable: true,
          recruit_closed: false,
          recruit_closed_tip: 'йӘ‘жүӢе·ІжӢӣж»ЎпјҢеҫ…е°ҸзЁӢеәҸеҒҡеӨ§еҒҡејәеҗҺдјҡе…¬е‘Ҡжү©жӢӣгҖӮ'
        },
        riderJoinMode: 'pending'
			}
		},
    watch: {
      // зҷ»еҪ•жҖҒеҸҳеҢ–еҗҺпјҢйҮҚж–°жӢүдёҖж¬Ўй’ұеҢ…пјҢйҒҝе…ҚйҰ–ж¬Ўиҝӣе…Ҙж—¶жңӘзҷ»еҪ•еҜјиҮҙй’ұеҢ…дёә 0 дё”еҗҺз»ӯдёҚеҲ·ж–°
      'userInfo._id': {
        immediate: true,
        handler: async function (val) {
          if (!val) return
          if (!this.walletStore) this.walletStore = useWalletStore()
          await this.walletStore.loadFromCloud()
        }
      }
    },
		async onShow() {
			this.univerifyStyle.authButton.title = "жң¬жңәеҸ·з ҒдёҖй”®з»‘е®ҡ"
			this.univerifyStyle.otherLoginButton.title = "е…¶д»–еҸ·з Ғз»‘е®ҡ"
			if (this.walletStore) {
				await this.walletStore.loadFromCloud()
			}
			await this.loadRiderGuide()
		},
		async onLoad(e) {
			if (e.showLoginManage) {
				this.showLoginManage = true //йҖҡиҝҮйЎөйқўдј еҸӮйҡҗи—Ҹзҷ»еҪ•&йҖҖеҮәзҷ»еҪ•жҢүй’®
			}
			//еҲӨж–ӯеҪ“еүҚз”ЁжҲ·жҳҜеҗҰжңүеҜҶз ҒпјҢеҗҰеҲҷе°ұдёҚжҳҫзӨәеҜҶз Ғдҝ®ж”№еҠҹиғҪ
			let res = await uniIdCo.getAccountInfo()
			this.hasPwd = res.isPasswordSet
			// еҲқе§ӢеҢ–й’ұеҢ… store
			this.walletStore = useWalletStore()
			await this.loadRiderGuide()
		},
		methods: {
			async loadRiderGuide() {
				try {
					const res = await riderService.getWithdrawGuide()
					if (res && res.code === 0 && res.data) {
						this.riderGuide = {
							title: res.data.title || 'жҸҗзҺ°иҜ·зӮ№жҲ‘зҡ„',
							tip: res.data.tip || 'жү«жҸҸдәҢз»ҙз Ғж·»еҠ йӘ‘жүӢзҫӨ',
							qr_file_id: res.data.qr_file_id || '',
							enable: res.data.enable !== false,
							recruit_closed: res.data.recruit_closed === true,
							recruit_closed_tip: res.data.recruit_closed_tip || 'йӘ‘жүӢе·ІжӢӣж»ЎпјҢеҫ…е°ҸзЁӢеәҸеҒҡеӨ§еҒҡејәеҗҺдјҡе…¬е‘Ҡжү©жӢӣгҖӮ'
						}
					}
				} catch (e) {}
			},
			openRiderJoinPopup(mode = 'pending') {
				this.riderJoinMode = mode
				this.$refs.riderJoinPopup && this.$refs.riderJoinPopup.open()
			},
			closeRiderJoinPopup() {
				this.$refs.riderJoinPopup && this.$refs.riderJoinPopup.close()
			},
			previewRiderGuideQr() {
				if (!this.riderGuide.qr_file_id) return
				uni.previewImage({ urls: [this.riderGuide.qr_file_id], current: this.riderGuide.qr_file_id })
			},
			enterRiderMode() {
				this.closeRiderJoinPopup()
				switchToRider()
				uni.reLaunch({ 
					url: '/pages/rider/hall',
					success: () => {
						uni.showToast({ title: 'е·ІеҲҮжҚўеҲ°йӘ‘жүӢз«Ҝ', icon: 'success', duration: 1500 })
					}
				})
			},
      // й»ҳи®Өжҳөз§°пјҡеҗҢеӯҰ + й•ҝеәҰдёә 3 зҡ„вҖңж•°еӯ—жҲ–иӢұж–ҮвҖқйҡҸжңәз»„еҗҲпјҢе№¶жҢү uid зј“еӯҳдҝқиҜҒзЁіе®ҡеұ•зӨә
			getDefaultNickname() {
				const uid = this.userInfo && this.userInfo._id ? String(this.userInfo._id) : ''
				if (!uid) return 'зӮ№еҮ»зҷ»еҪ•/е®Ңе–„иө„ж–ҷ'

				const cacheKey = `default_nickname_${uid}`
				const cached = uni.getStorageSync(cacheKey)
				if (cached && typeof cached === 'string') return cached

				const chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ'
				let code = ''
				for (let i = 0; i < 3; i++) {
					code += chars.charAt(Math.floor(Math.random() * chars.length))
				}

				const nickname = `еҗҢеӯҰ${code}`
				uni.setStorageSync(cacheKey, nickname)
				return nickname
			},
			login() {
				uni.navigateTo({
					url: '/uni_modules/uni-id-pages/pages/login/login-withoutpwd',
					complete: (e) => {
						// console.log(e);
					}
				})
			},
			logout() {
				mutations.logout()
			},
			bindMobileSuccess() {
				mutations.updateUserInfo()
			},
			changePassword() {
				uni.navigateTo({
					url: '/uni_modules/uni-id-pages/pages/userinfo/change_pwd/change_pwd',
					complete: (e) => {
						// console.log(e);
					}
				})
			},
			bindMobile() {
				// #ifdef APP-PLUS
				uni.preLogin({
					provider: 'univerify',
					success: this.univerify(), //йў„зҷ»еҪ•жҲҗеҠҹ
					fail: () => { // йў„зҷ»еҪ•еӨұиҙҘ
						this.bindMobileBySmsCode()
					}
				})
				// #endif

				// #ifdef MP-WEIXIN
				this.$refs['bind-mobile-by-sms'].open()
				// #endif

				// #ifdef H5
				//...еҺ»з”ЁйӘҢиҜҒз Ғз»‘е®ҡ
				this.bindMobileBySmsCode()
				// #endif
			},
			univerify() {
				uni.login({
					"provider": 'univerify',
					"univerifyStyle": this.univerifyStyle,
					success: async e => {
						uniIdCo.bindMobileByUniverify(e.authResult)
							.then(() => {
								mutations.updateUserInfo()
							})
							.catch(err => {
								uni.showToast({ title: err?.message || 'з»‘е®ҡеӨұиҙҘ', icon: 'none' })
							})
							.finally(() => {
								uni.closeAuthView()
							})
					},
					fail: (err) => {
						if (err.code == '30002' || err.code == '30001') {
							this.bindMobileBySmsCode()
						} else {
							uni.showToast({ title: err?.errMsg || 'ж“ҚдҪңе·ІеҸ–ж¶Ҳ', icon: 'none' })
						}
					}
				})
			},
			bindMobileBySmsCode() {
				uni.navigateTo({
					url: '/uni_modules/uni-id-pages/pages/userinfo/bind-mobile/bind-mobile'
				})
			},
			setNickname(nickname) {
				if (nickname) {
					mutations.updateUserInfo({
						nickname
					})
					this.setNicknameIng = false
					this.$refs.dialog.close()
				} else {
					this.$refs.dialog.open()
				}
			},
			deactivate(){
				uni.navigateTo({
					url:"/uni_modules/uni-id-pages/pages/userinfo/deactivate/deactivate"
				})
			},
      goOrders() {
        uni.reLaunch({
          url: '/pages/client/orders/list'
        })
      },
      goWallet() {
        if (!this.isRiderMode) {
          uni.showToast({ title: 'д»…йӘ‘жүӢеҸҜз”Ё', icon: 'none' })
          return
        }
        uni.navigateTo({ url: '/pages/common/wallet/index' })
      },
      goAddress() {
        uni.navigateTo({
          url: '/pages/common/address/list'
        })
      },
      goFavorite() {
        uni.showToast({ title: 'жҲ‘зҡ„ж”¶и—ҸпјҲеҫ…е®һзҺ°пјү', icon: 'none' })
      },
      goCoupon() {
        uni.showToast({ title: 'дјҳжғ еҲёпјҲеҫ…е®һзҺ°пјү', icon: 'none' })
      },
      goMessages() {
        uni.showToast({ title: 'ж¶ҲжҒҜйҖҡзҹҘпјҲеҫ…е®һзҺ°пјү', icon: 'none' })
      },
      goService() {
        this.$refs.servicePopup && this.$refs.servicePopup.open()
      },
      closeServicePopup() {
        this.$refs.servicePopup && this.$refs.servicePopup.close()
      },
      copyServicePhone() {
        uni.setClipboardData({
          data: this.servicePhone,
          success: () => {
            uni.showToast({ title: 'е·ІеӨҚеҲ¶', icon: 'success' })
          }
        })
      },
      callServicePhone() {
        uni.makePhoneCall({
          phoneNumber: this.servicePhone,
          fail: () => {
            uni.showToast({ title: 'жӢЁжү“еӨұиҙҘпјҢиҜ·йҮҚиҜ•', icon: 'none' })
          }
        })
      },
      onContact(e) {
        // йў„з•ҷеӣһи°ғпјҡеҸҜеңЁжӯӨи®°еҪ•жқҘжәҗжҲ–еҒҡеҹӢзӮ№
        // console.log('contact session from mine page', e)
      },
      goHelp() {
        uni.navigateTo({ url: '/pages/common/feedback/index' })
      },
      goSettings() {
        uni.showToast({ title: 'и®ҫзҪ®пјҲеҫ…е®һзҺ°пјү', icon: 'none' })
      },
      goAgreements() {
        uni.showActionSheet({
          itemList: ['з”ЁжҲ·жңҚеҠЎеҚҸи®®', 'йҡҗз§Ғж”ҝзӯ–'],
          success: (res) => {
            const url = res.tapIndex === 0 ? '/pages/common/legal/service' : '/pages/common/legal/privacy'
            uni.navigateTo({ url })
          }
        })
      },
      /**
       * еҲҮжҚўеҲ°йӘ‘жүӢз«Ҝ
       * - еҰӮжһңжңӘе®ҢжҲҗйӘ‘жүӢе®һеҗҚи®ӨиҜҒпјҢеҲҷе…Ҳи·іиҪ¬еҲ°и®ӨиҜҒйЎөйқў
       * - еҸӘжңүи®ӨиҜҒйҖҡиҝҮ(approved)еҗҺжүҚзңҹжӯЈеҲҮжҚўжЁЎејҸ
       */
      async goBecomeRider() {
        if (!this.userInfo || !this.userInfo._id) {
          uni.showToast({ title: 'иҜ·е…Ҳзҷ»еҪ•', icon: 'none' })
          return
        }

        try {
          await this.loadRiderGuide()

          const res = await riderService.getMyProfile()
          const profile = res && res.code === 0 ? res.data : null

          if (this.riderGuide.recruit_closed && (!profile || profile.status !== 'approved')) {
            uni.showModal({
              title: 'жҡӮеҒңжӢӣеӢҹ',
              content: this.riderGuide.recruit_closed_tip || 'йӘ‘жүӢе·ІжӢӣж»ЎпјҢеҫ…е°ҸзЁӢеәҸеҒҡеӨ§еҒҡејәеҗҺдјҡе…¬е‘Ҡжү©жӢӣгҖӮ',
              showCancel: false
            })
            return
          }

          if (!profile) {
            // жІЎжңүиө„ж–ҷж—¶пјҢеј•еҜјеҺ»еЎ«еҶҷи®ӨиҜҒдҝЎжҒҜ
            uni.navigateTo({ url: '/pages/rider/verify' })
            return
          }

          if (profile.status !== 'approved') {
            if (profile.status === 'pending') {
              uni.showToast({ title: 'и®ӨиҜҒе®Ўж ёдёӯпјҢиҜ·е…ҲеҠ зҫӨзӯүеҫ…йҖҡзҹҘ', icon: 'none' })
              this.openRiderJoinPopup('pending')
            } else {
              uni.showToast({ title: 'и®ӨиҜҒжңӘйҖҡиҝҮпјҢиҜ·дҝ®ж”№иө„ж–ҷеҗҺйҮҚжҸҗ', icon: 'none' })
              uni.navigateTo({ url: '/pages/rider/verify' })
            }
            return
          }
          this.enterRiderMode()
        } catch (e) {
          uni.showToast({ title: 'иҺ·еҸ–и®ӨиҜҒдҝЎжҒҜеӨұиҙҘпјҢиҜ·зЁҚеҗҺйҮҚиҜ•', icon: 'none' })
        }
      },
      /**
       * еҲҮеӣһз”ЁжҲ·з«Ҝ
       * 1. дҝ®ж”№жң¬ең°еӯҳеӮЁ user_mode дёә 'client'
       * 2. дҪҝз”Ё reLaunch и·іиҪ¬еҲ°з”ЁжҲ·з«ҜйҰ–йЎө
       */
      goClientMode() {
        switchToClient()
        uni.reLaunch({ 
          url: '/pages/client/home',
          success: () => {
            uni.showToast({
              title: 'е·ІеҲҮжҚўеҲ°з”ЁжҲ·з«Ҝ',
              icon: 'success',
              duration: 1500
            })
          }
        })
      },
			async bindThirdAccount(provider) {
				const uniIdCo = uniCloud.importObject("uni-id-co")
				const bindField = {
					weixin: 'wx_openid',
					alipay: 'ali_openid',
					apple: 'apple_openid',
					qq: 'qq_openid'
				}[provider.toLowerCase()]

				if (this.userInfo[bindField]) {
					await uniIdCo['unbind' + provider]()
					await mutations.updateUserInfo()
				} else {
					uni.login({
						provider: provider.toLowerCase(),
						onlyAuthorize: true,
						success: async e => {
							const res = await uniIdCo['bind' + provider]({
								code: e.code
							})
							if (res.errCode) {
								uni.showToast({
									title: res.errMsg || 'з»‘е®ҡеӨұиҙҘ',
									duration: 3000
								})
							}
							await mutations.updateUserInfo()
						},
						fail: async (err) => {
							uni.hideLoading()
							uni.showToast({ title: err?.errMsg || 'ж“ҚдҪңе·ІеҸ–ж¶Ҳ', icon: 'none' })
						}
					})
				}
			},
			realNameVerify () {
				uni.navigateTo({
					url: "/uni_modules/uni-id-pages/pages/userinfo/realname-verify/realname-verify"
				})
			}
		}
	}
</script>
